"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

export default function Home() {
  const [isRunning, setIsRunning] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);
  const [cpuState, setCpuState] = useState<any>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [emu, setEmu] = useState<any>(null);

  const addLog = useCallback((message: string) => {
    setLogs((prev) => [...prev.slice(-14), `[${new Date().toLocaleTimeString()}] ${message}`]);
  }, []);

  useEffect(() => {
    const initEmulator = async () => {
      try {
        const emulatorPackage = await import("typescript-gameboy-emulator");
        setEmu(emulatorPackage);
        emulatorPackage.joypad.init();
        if (canvasRef.current) {
          emulatorPackage.gpu.reset();
        }
        updateStateFromEmulator(emulatorPackage);
      } catch (error) {
        console.error("Failed to load emulator package:", error);
      }
    };
    initEmulator();
  }, []);

  const updateStateFromEmulator = useCallback((emuInstance: any) => {
    if (emuInstance) {
      const { cpu } = emuInstance;
      setCpuState({
        pc: cpu.pc, sp: cpu.sp,
        a: cpu.reg.a, b: cpu.reg.b, c: cpu.reg.c, d: cpu.reg.d, e: cpu.reg.e, h: cpu.reg.h, l: cpu.reg.l, f: cpu.reg.f
      });
    }
  }, []);

  useEffect(() => {
    let interval: any;
    if (isRunning && emu) {
      interval = setInterval(() => updateStateFromEmulator(emu), 500);
    }
    return () => clearInterval(interval);
  }, [isRunning, emu, updateStateFromEmulator]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && emu) {
      const buffer = await file.arrayBuffer();
      const romData = new Uint8Array(buffer);
      if (emu.emulator._rafId) cancelAnimationFrame(emu.emulator._rafId);
      await emu.emulator.run(romData);
      setIsRunning(true);
      addLog(`📥 Loaded ROM: ${file.name}`);
    }
  };

  const pressKey = (key: string) => {
    if (emu) {
      emu.joypad.keyDown(key);
      addLog(`Pressed ${key}`);
    }
  };

  const releaseKey = (key: string) => {
    if (emu) emu.joypad.keyUp(key);
  };

  const formatHex = (value: number, digits: number = 2) => 
    `0x${(value || 0).toString(16).toUpperCase().padStart(digits, '0')}`;

  return (
    <div className="min-h-screen bg-black flex flex-col items-center justify-center p-4 md:p-12 font-sans selection:bg-blue-500/30 overflow-x-hidden">
      
      {/* Main Game Section */}
      <div className="flex flex-col items-center gap-12 w-full max-w-4xl">
        
        {/* Scaled Display Section */}
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-purple-600 rounded-xl blur opacity-25 group-hover:opacity-40 transition duration-1000"></div>
          <div className="relative bg-zinc-900 rounded-xl p-2 border border-zinc-800 shadow-2xl">
            <div className="aspect-[160/144] w-full max-w-[640px] md:w-[640px] bg-black rounded-lg overflow-hidden border-2 border-zinc-800 flex items-center justify-center relative">
              <canvas 
                id="screen" 
                ref={canvasRef}
                width="160" 
                height="144" 
                className="w-full h-full image-render-pixelated shadow-inner"
              />
              {!isRunning && (
                <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center text-center p-8">
                  <div className="text-blue-500 text-6xl mb-6 animate-pulse">🕹️</div>
                  <h2 className="text-2xl font-black text-white italic tracking-tighter mb-4">INSERT CARTRIDGE</h2>
                  <div className="relative group overflow-hidden rounded-full">
                    <input type="file" accept=".gb,.gbc" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" />
                    <Button className="bg-blue-600 text-white hover:bg-blue-700 font-bold px-12 rounded-full shadow-[0_0_30px_rgba(37,99,235,0.4)]">
                      LOAD ROM
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Controller Section */}
        <div className="w-full max-w-[640px] flex flex-col items-center gap-12 py-8 bg-zinc-900/20 rounded-[40px] border border-zinc-800/50 backdrop-blur-sm">
          <div className="flex justify-between items-center w-full px-12">
            
            {/* D-Pad */}
            <div className="relative w-32 h-32 scale-125">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-32 bg-zinc-800 rounded-lg shadow-xl border border-zinc-700/50" />
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-10 bg-zinc-800 rounded-lg shadow-xl border border-zinc-700/50" />
              
              <button 
                onMouseDown={() => pressKey('ArrowUp')} onMouseUp={() => releaseKey('ArrowUp')} 
                className="absolute top-0 left-11 w-10 h-11 active:bg-blue-500/20 transition-colors rounded-t-lg" 
              />
              <button 
                onMouseDown={() => pressKey('ArrowDown')} onMouseUp={() => releaseKey('ArrowDown')} 
                className="absolute bottom-0 left-11 w-10 h-11 active:bg-blue-500/20 transition-colors rounded-b-lg" 
              />
              <button 
                onMouseDown={() => pressKey('ArrowLeft')} onMouseUp={() => releaseKey('ArrowLeft')} 
                className="absolute left-0 top-11 w-11 h-10 active:bg-blue-500/20 transition-colors rounded-l-lg" 
              />
              <button 
                onMouseDown={() => pressKey('ArrowRight')} onMouseUp={() => releaseKey('ArrowRight')} 
                className="absolute right-0 top-11 w-11 h-10 active:bg-blue-500/20 transition-colors rounded-r-lg" 
              />
              
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-8 bg-zinc-800 rounded-full border border-zinc-700/30 shadow-inner" />
            </div>

            {/* Action Buttons */}
            <div className="flex gap-8 scale-125">
              <div className="flex flex-col items-center gap-3">
                <button 
                  onMouseDown={() => pressKey('KeyX')} onMouseUp={() => releaseKey('KeyX')}
                  className="w-16 h-16 bg-zinc-800 rounded-full shadow-[0_6px_0_rgba(0,0,0,0.4)] active:shadow-none active:translate-y-1.5 transition-all border border-zinc-700/50 flex items-center justify-center group"
                >
                  <span className="text-zinc-500 font-black group-active:text-blue-500 transition-colors">B</span>
                </button>
              </div>
              <div className="flex flex-col items-center gap-3">
                <button 
                  onMouseDown={() => pressKey('KeyZ')} onMouseUp={() => releaseKey('KeyZ')}
                  className="w-16 h-16 bg-zinc-800 rounded-full shadow-[0_6px_0_rgba(0,0,0,0.4)] active:shadow-none active:translate-y-1.5 transition-all border border-zinc-700/50 flex items-center justify-center group"
                >
                  <span className="text-zinc-500 font-black group-active:text-blue-500 transition-colors">A</span>
                </button>
              </div>
            </div>
          </div>

          {/* Select/Start */}
          <div className="flex justify-center gap-12">
            <div className="flex flex-col items-center gap-2">
              <button 
                onMouseDown={() => pressKey('ShiftLeft')} onMouseUp={() => releaseKey('ShiftLeft')}
                className="w-16 h-4 bg-zinc-800 rounded-full shadow-[0_3px_0_rgba(0,0,0,0.4)] active:shadow-none active:translate-y-1 transition-all border border-zinc-700/50"
              />
              <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.2em]">Select</span>
            </div>
            <div className="flex flex-col items-center gap-2">
              <button 
                onMouseDown={() => pressKey('Enter')} onMouseUp={() => releaseKey('Enter')}
                className="w-16 h-4 bg-zinc-800 rounded-full shadow-[0_3px_0_rgba(0,0,0,0.4)] active:shadow-none active:translate-y-1 transition-all border border-zinc-700/50"
              />
              <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.2em]">Start</span>
            </div>
          </div>
        </div>

        {/* Dashboard Footer */}
        <div className="w-full grid grid-cols-1 md:grid-cols-2 gap-4">
          <Card className="bg-zinc-900/40 border-zinc-800 text-zinc-100">
            <CardHeader className="py-2 border-b border-zinc-800/50">
              <CardTitle className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">CPU State</CardTitle>
            </CardHeader>
            <CardContent className="p-3 grid grid-cols-4 gap-2 font-mono text-xs">
              <div className="flex flex-col"><span className="text-zinc-600 text-[8px]">AF</span> <span>{formatHex((cpuState?.a << 8) | cpuState?.f, 4)}</span></div>
              <div className="flex flex-col"><span className="text-zinc-600 text-[8px]">BC</span> <span>{formatHex((cpuState?.b << 8) | cpuState?.c, 4)}</span></div>
              <div className="flex flex-col"><span className="text-zinc-600 text-[8px]">DE</span> <span>{formatHex((cpuState?.d << 8) | cpuState?.e, 4)}</span></div>
              <div className="flex flex-col"><span className="text-zinc-600 text-[8px]">HL</span> <span>{formatHex((cpuState?.h << 8) | cpuState?.l, 4)}</span></div>
            </CardContent>
          </Card>
          <Card className="bg-zinc-900/40 border-zinc-800 text-zinc-100">
            <CardHeader className="py-2 border-b border-zinc-800/50">
              <CardTitle className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">System Events</CardTitle>
            </CardHeader>
            <CardContent className="p-3 h-12 overflow-y-auto scrollbar-none font-mono text-[10px] text-zinc-400">
              {logs.slice(-1).map((log, i) => <div key={i}>{log}</div>)}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}
